import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, useNavigate, Link, useLocation } from 'react-router-dom';
import axios from 'axios';
import './App.css';

// --- THÀNH PHẦN DÙNG CHUNG: SIDEBAR ---
function Sidebar() {
    const location = useLocation();

    // Hàm kiểm tra xem link có đang được chọn không để đổi màu
    const activeClass = (path) => location.pathname === path ? "active-link" : "";

    return (
        <div className="sidebar">
            <div className="sidebar-header">MyAdmin</div>
            <ul className="sidebar-menu">
                <li className={activeClass('/dashboard')}><Link to="/dashboard">Dashboard</Link></li>
                <li className={activeClass('/employees')}><Link to="/employees">Hồ sơ nhân viên</Link></li>
                <li className={activeClass('/attendance')}><Link to="/attendance">Chấm công</Link></li>
                <li className={activeClass('/contracts')}><Link to="/contracts">Hợp đồng</Link></li>
                <li className={activeClass('/salary')}><Link to="/salary">Bảng lương</Link></li>
                <li className={activeClass('/accounts')}><Link to="/accounts">Tài khoản</Link></li>
            </ul>
        </div>
    );
}

// --- THÀNH PHẦN DÙNG CHUNG: TOPBAR ---
function TopBar() {
    return (
        <div className="top-bar">
            <span className="system-title">HỆ THỐNG QUẢN LÝ NHÂN SỰ</span>
            <div className="user-info">
                <span>Chào Admin | <Link to="/" style={{ color: '#fff', textDecoration: 'none' }}>Đăng xuất</Link></span>
            </div>
        </div>
    );
}

// --- TRANG ĐĂNG NHẬP ---
function LoginPage() {
    const navigate = useNavigate();
    const [user, setUser] = useState('');
    const [pass, setPass] = useState('');

    const handleLogin = (e) => {
        e.preventDefault();
        navigate('/dashboard'); // Cho phép vào thẳng dashboard
    };

    return (
        <div className="login-page">
            <div className="login-card">
                <h2>HỆ THỐNG NHÂN SỰ</h2>
                <form onSubmit={handleLogin}>
                    <div className="input-group">
                        <label>Username</label>
                        <input type="text" value={user} onChange={(e) => setUser(e.target.value)} required />
                    </div>
                    <div className="input-group">
                        <label>Password</label>
                        <input type="password" value={pass} onChange={(e) => setPass(e.target.value)} required />
                    </div>
                    <button type="submit" className="btn-login">ĐĂNG NHẬP</button>
                </form>
            </div>
        </div>
    );
}

// --- TRANG DASHBOARD (TỔNG QUAN) ---
function DashboardPage() {
    const [stats, setStats] = useState({ employees: 0, teachers: 0 });
    const [announcements, setAnnouncements] = useState(() => {
        const saved = localStorage.getItem('announcements');
        return saved ? JSON.parse(saved) : [];
    });
    const [newAnnouncement, setNewAnnouncement] = useState('');

    useEffect(() => {
        // Lấy dữ liệu nhân viên từ localStorage
        const employeeDataStr = localStorage.getItem('employeeData');
        if (employeeDataStr) {
            const employees = JSON.parse(employeeDataStr);
            const numTeachers = employees.filter(emp => emp.position === 'Giảng viên').length;
            setStats({ employees: employees.length, teachers: numTeachers });
        } else {
            // Fallback
            axios.get("http://localhost:8080/api/employees")
                .then(res => {
                    const data = res.data;
                    const numTeachers = data.filter(emp => emp.position === 'Giảng viên').length;
                    setStats({ employees: data.length, teachers: numTeachers });
                    localStorage.setItem('employeeData', JSON.stringify(data));
                })
                .catch(err => console.error("Lỗi kết nối Backend:", err));
        }
    }, []);

    useEffect(() => {
        localStorage.setItem('announcements', JSON.stringify(announcements));
    }, [announcements]);

    const handleSendAnnouncement = (e) => {
        e.preventDefault();
        if (!newAnnouncement.trim()) return;

        const newMsg = {
            id: Date.now(),
            text: newAnnouncement,
            date: new Date().toLocaleString('vi-VN')
        };
        setAnnouncements([newMsg, ...announcements]);
        setNewAnnouncement('');
    };

    return (
        <div className="dashboard-layout">
            <Sidebar />
            <div className="main-content">
                <TopBar />
                <div className="content-body">
                    <div className="stats-grid">
                        <div className="stat-card border-blue">
                            <p>SỐ NHÂN VIÊN</p>
                            <h4>{stats.employees}</h4>
                        </div>
                        <div className="stat-card border-green">
                            <p>SỐ GIẢNG VIÊN (TEACHERS)</p>
                            <h4>{stats.teachers}</h4>
                        </div>
                    </div>
                    <div className="welcome-section" style={{ display: 'flex', gap: '20px', flexWrap: 'wrap' }}>
                        <div style={{ flex: '1', minWidth: '300px' }}>
                            <h3>Dashboard Tổng Quan</h3>
                            <p>Chào mừng bạn quay trở lại hệ thống quản trị.</p>
                        </div>
                        <div style={{ flex: '1', minWidth: '350px', backgroundColor: '#f8fafc', padding: '20px', borderRadius: '12px', border: '1px solid #e2e8f0' }}>
                            <h4 style={{ margin: '0 0 15px 0', color: '#1e293b' }}>Gửi thông báo tới toàn thể</h4>
                            <form onSubmit={handleSendAnnouncement} style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                                <textarea
                                    value={newAnnouncement}
                                    onChange={(e) => setNewAnnouncement(e.target.value)}
                                    placeholder="Nhập nội dung thông báo..."
                                    style={{ width: '100%', padding: '12px', borderRadius: '8px', border: '1px solid #cbd5e1', fontFamily: 'inherit', resize: 'vertical', minHeight: '80px', boxSizing: 'border-box' }}
                                    required
                                />
                                <button type="submit" className="btn-primary" style={{ alignSelf: 'flex-end', padding: '8px 16px', fontSize: '0.9rem' }}>Gửi đi</button>
                            </form>

                            {announcements.length > 0 && (
                                <div style={{ marginTop: '20px' }}>
                                    <h5 style={{ margin: '0 0 10px 0', borderBottom: '1px solid #e2e8f0', paddingBottom: '5px' }}>Lịch sử thông báo</h5>
                                    <ul style={{ listStyle: 'none', padding: 0, margin: 0, maxHeight: '200px', overflowY: 'auto' }}>
                                        {announcements.map(msg => (
                                            <li key={msg.id} style={{ padding: '10px', borderBottom: '1px solid #f1f5f9', fontSize: '0.9rem' }}>
                                                <p style={{ margin: '0 0 5px 0', color: '#334155' }}>{msg.text}</p>
                                                <small style={{ color: '#94a3b8' }}>{msg.date}</small>
                                            </li>
                                        ))}
                                    </ul>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

// --- TRANG HỒ SƠ NHÂN VIÊN ---
function EmployeePage() {
    const [employees, setEmployees] = useState(() => {
        const saved = localStorage.getItem('employeeData');
        return saved ? JSON.parse(saved) : [];
    });
    const [showModal, setShowModal] = useState(false);
    const [newEmployee, setNewEmployee] = useState({ fullName: '', department: 'Nhân sự', position: 'Nhân viên' });

    useEffect(() => {
        if (!localStorage.getItem('employeeData')) {
            axios.get("http://localhost:8080/api/employees")
                .then(res => {
                    setEmployees(res.data);
                    localStorage.setItem('employeeData', JSON.stringify(res.data));
                })
                .catch(err => console.error(err));
        }
    }, []);

    useEffect(() => {
        localStorage.setItem('employeeData', JSON.stringify(employees));
    }, [employees]);

    const handleSaveEmployee = (e) => {
        e.preventDefault();
        // Giả lập lưu thành công (Nếu có API POST thì gọi axios.post ở đây)
        const newEmpWithId = { ...newEmployee, id: Date.now() };
        setEmployees([...employees, newEmpWithId]);
        setShowModal(false);
        setNewEmployee({ fullName: '', department: 'Nhân sự', position: 'Nhân viên' });
    };

    return (
        <div className="dashboard-layout">
            <Sidebar />
            <div className="main-content">
                <TopBar />
                <div className="content-body">
                    <div className="header-action">
                        <h3>Hồ sơ nhân viên / giảng viên</h3>
