// --- 5. TRANG QUẢN LÝ HỢP ĐỒNG ---
function ContractPage() {
    const [contracts, setContracts] = useState(() => {
        const saved = localStorage.getItem('contractData');
        return saved ? JSON.parse(saved) : [
            { id: 1, maHD: 'HD-001', nhanVien: 'Nguyễn Văn A', loaiHopDong: 'Vô thời hạn', ngayKy: '01/01/2024', trangThai: 'Đang hiệu lực' }
        ];
    });
    const [showModal, setShowModal] = useState(false);
    const [newContract, setNewContract] = useState({ maHD: '', nhanVien: '', loaiHopDong: '1 năm', ngayKy: '', trangThai: 'Đang hiệu lực' });

    useEffect(() => {
        localStorage.setItem('contractData', JSON.stringify(contracts));
    }, [contracts]);

    const handleSaveContract = (e) => {
        e.preventDefault();
        const contractWithId = { ...newContract, id: Date.now() };
        setContracts([...contracts, contractWithId]);
        setShowModal(false);
        setNewContract({ maHD: '', nhanVien: '', loaiHopDong: '1 năm', ngayKy: '', trangThai: 'Đang hiệu lực' });
    };

    return (
        <div className="dashboard-layout">
            <Sidebar />
            <div className="main-content">
                <TopBar />
                <div className="content-body">
                    <div className="header-action">
                        <h3>Quản lý hợp đồng lao động</h3>
                        <button className="btn-primary" onClick={() => setShowModal(true)}>+ Tạo hợp đồng mới</button>
                    </div>
                    <div className="card-info shadow-sm">
                        <p>Danh sách hợp đồng sắp hết hạn: <strong>3 hợp đồng</strong></p>
                    </div>
                    <table className="data-table">
                        <thead>
                            <tr>
                                <th>Mã HĐ</th>
                                <th>Nhân viên</th>
                                <th>Loại hợp đồng</th>
                                <th>Ngày ký</th>
                                <th>Trạng thái</th>
                            </tr>
                        </thead>
                        <tbody>
                            {contracts.map(contract => (
                                <tr key={contract.id}>
                                    <td className="font-bold">{contract.maHD}</td>
                                    <td>{contract.nhanVien}</td>
                                    <td>{contract.loaiHopDong}</td>
                                    <td>{contract.ngayKy}</td>
                                    <td>
                                        <span className={contract.trangThai === "Đang hiệu lực" ? "status-active" : ""}>
                                            {contract.trangThai}
                                        </span>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Modal Thêm Hợp Đồng */}
            {showModal && (
                <div className="modal-overlay">
                    <div className="modal-content">
                        <h3>Tạo hợp đồng mới</h3>
                        <form onSubmit={handleSaveContract}>
                            <div className="form-group">
                                <label>Mã Hợp Đồng</label>
                                <input type="text" value={newContract.maHD} onChange={e => setNewContract({ ...newContract, maHD: e.target.value })} required placeholder="VD: HD-002" />
                            </div>
                            <div className="form-group">
                                <label>Tên Nhân Viên</label>
                                <input type="text" value={newContract.nhanVien} onChange={e => setNewContract({ ...newContract, nhanVien: e.target.value })} required placeholder="Nhập tên nhân viên..." />
                            </div>
                            <div className="form-group">
                                <label>Loại hợp đồng</label>
                                <select value={newContract.loaiHopDong} onChange={e => setNewContract({ ...newContract, loaiHopDong: e.target.value })}>
                                    <option value="1 năm">1 năm</option>
                                    <option value="3 năm">3 năm</option>
                                    <option value="Vô thời hạn">Vô thời hạn</option>
                                    <option value="Thử việc">Thử việc</option>
                                </select>
                            </div>
                            <div className="form-group">
                                <label>Ngày ký</label>
                                <input type="date" value={newContract.ngayKy} onChange={e => setNewContract({ ...newContract, ngayKy: e.target.value })} required />
                            </div>
                            <div className="form-actions">
                                <button type="button" className="btn-secondary" onClick={() => setShowModal(false)}>Hủy</button>
                                <button type="submit" className="btn-primary">Lưu hợp đồng</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

// --- 6. TRANG BẢNG LƯƠNG (Tính toán & Quản lý) ---
function SalaryPage() {
    // Tải dữ liệu từ localStorage, nếu không có lấy dữ liệu mẫu
    const initialData = JSON.parse(localStorage.getItem('salaryData')) || [
        { id: 1, name: 'Trần Thị B', base: 15000000, allowance: 2000000, deduction: 500000, net: 16500000 }
    ];

    const [salaries, setSalaries] = useState(initialData);

    // Lưu lại tiến trình mỗi khi mảng salaries thay đổi
    useEffect(() => {
        localStorage.setItem('salaryData', JSON.stringify(salaries));
    }, [salaries]);

    const handleCalculate = () => {
        // Giả lập tính lương bằng cách thêm 1 nhân viên mới vào danh sách
        const newSalary = {
            id: Date.now(),
            name: 'Nhân viên Mới ' + Math.floor(Math.random() * 100),
            base: 10000000,
            allowance: 1000000,
            deduction: 200000,
            net: 10800000
        };
        setSalaries([...salaries, newSalary]);
    };

    const handleExportCSV = () => {
        // Xuất dữ liệu sang file CSV
        const headers = ["Nhân viên", "Lương cơ bản", "Phụ cấp", "Khấu trừ", "Thực nhận"];
        const csvContent = [
            headers.join(","),
            ...salaries.map(s => `"${s.name}",${s.base},${s.allowance},${s.deduction},${s.net}`)
        ].join("\n");

        const blob = new Blob(["\uFEFF" + csvContent], { type: 'text/csv;charset=utf-8;' }); // \uFEFF hỗ trợ font Tiếng Việt
        const link = document.createElement("a");
        const url = URL.createObjectURL(blob);
        link.setAttribute("href", url);
        link.setAttribute("download", `bang_luong_thang_${new Date().getMonth() + 1}.csv`);
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const formatCurrency = (amount) => {
        return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(amount);
    };

    return (
        <div className="dashboard-layout">
            <Sidebar />
            <div className="main-content">
                <TopBar />
                <div className="content-body">
                    <div className="header-action">
                        <h3>Bảng lương tháng {new Date().getMonth() + 1}</h3>
                        <div>
                            <button className="btn-secondary" style={{ marginRight: '10px' }} onClick={handleExportCSV}>Xuất báo cáo (CSV)</button>
                            <button className="btn-primary" onClick={handleCalculate}>Tính lương</button>
                        </div>
                    </div>
                    <table className="data-table">
                        <thead>
                            <tr>
                                <th>Nhân viên</th>
                                <th>Lương cơ bản</th>
                                <th>Phụ cấp</th>
                                <th>Khấu trừ</th>
                                <th>Thực nhận</th>
                            </tr>
                        </thead>
                        <tbody>
                            {salaries.map(s => (
                                <tr key={s.id}>
                                    <td className="font-bold">{s.name}</td>
                                    <td>{formatCurrency(s.base)}</td>
                                    <td>{formatCurrency(s.allowance)}</td>
                                    <td>{formatCurrency(s.deduction)}</td>
                                    <td style={{ color: '#1cc88a', fontWeight: 'bold' }}>{formatCurrency(s.net)}</td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

